woodmartThemeModule.waitlistTable=function(){var e=document.querySelector(".wd-wtl-table");e&&e.querySelectorAll(".wd-wtl-unsubscribe").forEach(function(t){t.addEventListener("click",function(t){t.preventDefault();var o=this;e.parentNode.querySelector(".wd-loader-overlay").classList.add("wd-loading"),jQuery.ajax({url:woodmart_settings.ajaxurl,data:{action:"woodmart_remove_from_waitlist_in_my_account",product_id:o.dataset.productId},method:"POST",success:function(t){if(t&&(t.success&&o.closest("tr").remove(),t.data.content)){tempDiv=document.createElement("div"),tempDiv.innerHTML=t.data.content;var r=tempDiv.querySelector(".wd-wtl-content").childNodes;e.parentNode.replaceChildren(...r)}},error:function(){console.error("ajax remove from waitlist error")},complete:function(){e.parentNode.querySelector(".wd-loader-overlay").classList.remove("wd-loading")}})})})},window.addEventListener("load",function(){woodmartThemeModule.waitlistTable()});